"use client";

import { createElement, useMemo } from "react";
import {
  StateProvider,
  ActionProvider,
  VisibilityProvider,
  ValidationProvider,
  Renderer,
  defineRegistry,
  useBoundProp,
} from "@json-render/react";
import { defineCatalog } from "@json-render/core";
import { schema } from "@json-render/react/schema";
import { z } from "zod";
import { useRhfStateStore } from "./use-rhf-state-store";
import { STRUCTURAL_COMPONENTS } from "../shared/built-in-structural";
import { cn } from "@/lib/utils";
import type { FormSchema, FieldComponent } from "./types";

// ─── Structural catalog entries ───────────────────────────────────────────────

const STRUCTURAL_CATALOG_ENTRIES = Object.fromEntries(
  Object.keys(STRUCTURAL_COMPONENTS).map((key) => [
    key,
    { props: z.record(z.string(), z.unknown()), description: key, slots: ["default"] },
  ])
) as Record<string, { props: ReturnType<typeof z.record>; description: string; slots: string[] }>;

// ─── FieldComponent wrapper ───────────────────────────────────────────────────

function wrapFieldComponent(Component: FieldComponent) {
  return function FieldWrapper({
    props,
    bindings,
  }: {
    props: Record<string, unknown>;
    bindings?: Record<string, string>;
  }) {
    const [value, setValue] = useBoundProp(props.value, bindings?.value);
    return createElement(Component, { ...props, value, onChange: setValue });
  };
}

// ─── Registry factory ─────────────────────────────────────────────────────────

function createFieldRegistry(customFields: Record<string, FieldComponent> = {}) {
  const fieldCatalogEntries = Object.fromEntries(
    Object.keys(customFields).map((key) => [
      key,
      { props: z.record(z.string(), z.unknown()), description: key },
    ])
  ) as Record<string, { props: ReturnType<typeof z.record>; description: string }>;

  const catalog = defineCatalog(schema, {
    components: {
      ...STRUCTURAL_CATALOG_ENTRIES,
      ...fieldCatalogEntries,
    } as any, // eslint-disable-line @typescript-eslint/no-explicit-any
    actions: {},
  });

  const wrappedCustom = Object.fromEntries(
    Object.entries(customFields).map(([key, Component]) => [
      key,
      wrapFieldComponent(Component),
    ])
  );

  const { registry } = defineRegistry(catalog, {
    components: {
      ...STRUCTURAL_COMPONENTS,
      ...wrappedCustom,
    } as any, // eslint-disable-line @typescript-eslint/no-explicit-any
  });

  return registry;
}

// ─── FormRenderer ─────────────────────────────────────────────────────────────

export interface FormRendererProps {
  schema: FormSchema;
  onSubmit: (data: Record<string, unknown>) => void | Promise<void>;
  defaultValues?: Record<string, unknown>;
  /** Plain React field components (FieldComponent interface). Auto-wrapped with state binding. */
  customFields?: Record<string, FieldComponent>;
  className?: string;
}

export function FormRenderer({
  schema,
  onSubmit,
  defaultValues,
  customFields,
  className,
}: FormRendererProps) {
  const initialValues = { ...schema.state, ...defaultValues };
  const { store, form } = useRhfStateStore(initialValues);

  const registry = useMemo(
    () => createFieldRegistry(customFields),
    [] // eslint-disable-line react-hooks/exhaustive-deps
  );

  const handleSubmit = form.handleSubmit(async (data) => {
    await onSubmit(data);
  });

  return (
    <StateProvider store={store}>
      <ActionProvider
        handlers={{
          submit: async () => {
            await handleSubmit();
          },
        }}
      >
        <VisibilityProvider>
          <ValidationProvider>
            <form onSubmit={(e) => e.preventDefault()} className={cn("w-full", className)} noValidate>
              <Renderer spec={schema} registry={registry} />
            </form>
          </ValidationProvider>
        </VisibilityProvider>
      </ActionProvider>
    </StateProvider>
  );
}

import type { Spec } from "@json-render/react";

export interface FormSchema extends Spec {
  title?: string;
  description?: string;
}

// Open string type — built-in values documented, custom types accepted.
// Built-ins: "Input" | "Textarea" | "Select" | "Checkbox" | "Radio" | "Switch" | "Slider"
export type FieldType = string;

export interface CanvasField {
  kind: "field";
  id: string;
  elementKey: string;
  fieldType: FieldType;
  props: Record<string, unknown>;
}

export interface CanvasGrid {
  kind: "grid";
  id: string;
  elementKey: string;
  columns: 2 | 3;
  fields: CanvasField[];
}

export type CanvasItem = CanvasField | CanvasGrid;

export interface StackConfig {
  gap: "none" | "sm" | "md" | "lg" | "xl";
  align?: "start" | "center" | "end" | "stretch";
  justify?: "start" | "center" | "end" | "between" | "around";
}

export interface ButtonConfig {
  label: string;
  variant: "primary" | "secondary" | "outline" | "ghost" | "danger";
  disabled: boolean;
}

export interface FormBuilderState {
  items: CanvasItem[];
  selectedFieldId: string | null;
  formTitle: string;
  formDescription: string;
  stackConfig: StackConfig;
  buttonConfig: ButtonConfig;
}

export interface ConfigurableProp {
  key: string;
  label: string;
  inputType: "text" | "select" | "boolean" | "number" | "options-list";
  options?: string[];
}

// Simple props passed to every custom field component.
// Consumers implement this interface — no @json-render knowledge required.
export interface FieldComponentProps {
  value: unknown;
  onChange: (value: unknown) => void;
  [key: string]: unknown;
}

export type FieldComponent = React.ComponentType<FieldComponentProps>;

export interface FormFieldDefinition {
  fieldType: FieldType;
  displayName: string;
  icon: React.ComponentType<{ className?: string }>;
  // Built-ins: "text" | "choice" | "toggle" | "numeric" — custom categories accepted.
  category: string;
  defaultProps: Record<string, unknown>;
  // Which prop to $bindState — defaults to "value" if omitted
  boundProp?: string;
  // Default value for the bound prop in form state — defaults to ""
  defaultValue?: unknown;
  // Structural components (Separator, Heading, Text, Alert) — no state binding
  isStructural?: boolean;
  configurableProps: ConfigurableProp[];
}

"use client";

import { useMemo, useRef } from "react";
import { useForm } from "react-hook-form";
import type { StateStore, StateModel } from "@json-render/react";

function getByJsonPointer(obj: Record<string, unknown>, path: string): unknown {
  if (!path || path === "/") return obj;
  const parts = path.replace(/^\//, "").split("/");
  let current: unknown = obj;
  for (const part of parts) {
    if (current == null || typeof current !== "object") return undefined;
    current = (current as Record<string, unknown>)[part];
  }
  return current;
}

function setByJsonPointer(
  obj: Record<string, unknown>,
  path: string,
  value: unknown
): Record<string, unknown> {
  if (!path || path === "/") return obj;
  const parts = path.replace(/^\//, "").split("/");
  const next = { ...obj };
  let current: Record<string, unknown> = next;
  for (let i = 0; i < parts.length - 1; i++) {
    const part = parts[i];
    current[part] = { ...(current[part] as Record<string, unknown>) };
    current = current[part] as Record<string, unknown>;
  }
  current[parts[parts.length - 1]] = value;
  return next;
}

export function useRhfStateStore(defaultValues: Record<string, unknown> = {}) {
  const form = useForm<Record<string, unknown>>({
    defaultValues,
    mode: "onBlur",
  });

  const listenersRef = useRef(new Set<() => void>());
  const snapshotRef = useRef<StateModel>({ ...defaultValues });

  form.watch((values) => {
    snapshotRef.current = values as StateModel;
    listenersRef.current.forEach((l) => l());
  });

  const store = useMemo<StateStore>(
    () => ({
      get: (path) => getByJsonPointer(snapshotRef.current, path),

      set: (path, value) => {
        const key = path.replace(/^\//, "");
        form.setValue(key as never, value as never, {
          shouldValidate: true,
          shouldDirty: true,
        });
        snapshotRef.current = setByJsonPointer(snapshotRef.current, path, value);
        listenersRef.current.forEach((l) => l());
      },

      update: (updates) => {
        let next = snapshotRef.current;
        Object.entries(updates).forEach(([path, value]) => {
          const key = path.replace(/^\//, "");
          form.setValue(key as never, value as never, {
            shouldValidate: true,
            shouldDirty: true,
          });
          next = setByJsonPointer(next, path, value);
        });
        snapshotRef.current = next;
        listenersRef.current.forEach((l) => l());
      },

      getSnapshot: () => snapshotRef.current,

      subscribe: (listener) => {
        listenersRef.current.add(listener);
        return () => listenersRef.current.delete(listener);
      },
    }),
    // eslint-disable-next-line react-hooks/exhaustive-deps
    []
  );

  return { store, form };
}

"use client";

import { cn } from "@/lib/utils";
import { Button as ShadcnButton } from "@/components/ui/button";

// ─── Types ────────────────────────────────────────────────────────────────────

type StructuralComponent<P extends Record<string, unknown> = Record<string, unknown>> = (args: {
  props: P;
  children?: React.ReactNode;
  emit?: (event: string) => void;
}) => React.ReactElement | null;

// ─── Stack ────────────────────────────────────────────────────────────────────

const GAP = { none: "gap-0", sm: "gap-2", md: "gap-3", lg: "gap-4", xl: "gap-6" } as const;
const ALIGN = { start: "items-start", center: "items-center", end: "items-end", stretch: "items-stretch" } as const;
const JUSTIFY = { start: "", center: "justify-center", end: "justify-end", between: "justify-between", around: "justify-around" } as const;

export const Stack: StructuralComponent = ({ props, children }) => (
  <div
    className={cn(
      "@container/stack flex",
      props.direction === "horizontal" ? "flex-row flex-wrap" : "flex-col",
      GAP[(props.gap as keyof typeof GAP) ?? "md"] ?? "gap-3",
      ALIGN[(props.align as keyof typeof ALIGN)] ?? "",
      JUSTIFY[(props.justify as keyof typeof JUSTIFY)] ?? "",
      props.className as string
    )}
  >
    {children}
  </div>
);

// ─── Grid ─────────────────────────────────────────────────────────────────────

const GRID_COLS: Record<number, string> = {
  1: "grid-cols-1", 2: "grid-cols-2", 3: "grid-cols-3",
  4: "grid-cols-4", 5: "grid-cols-5", 6: "grid-cols-6",
};
const GRID_GAP = { sm: "gap-2", md: "gap-3", lg: "gap-4", xl: "gap-6" } as const;

export const Grid: StructuralComponent = ({ props, children }) => {
  const n = Math.max(1, Math.min(6, (props.columns as number) ?? 1));
  return (
    <div
      className={cn(
        "grid @max-sm/stack:grid-cols-1",
        GRID_COLS[n],
        GRID_GAP[(props.gap as keyof typeof GRID_GAP) ?? "md"] ?? "gap-3",
        props.className as string
      )}
    >
      {children}
    </div>
  );
};

// ─── Button ───────────────────────────────────────────────────────────────────

const BTN_VARIANT_MAP: Record<string, "default" | "secondary" | "destructive" | "outline" | "ghost"> = {
  primary: "default",
  secondary: "secondary",
  danger: "destructive",
  outline: "outline",
  ghost: "ghost",
};

export const Button: StructuralComponent = ({ props, emit }) => (
  <ShadcnButton
    type="submit"
    variant={BTN_VARIANT_MAP[(props.variant as string) ?? "primary"] ?? "default"}
    disabled={(props.disabled as boolean) ?? false}
    onClick={() => emit?.("press")}
    className={props.className as string}
  >
    {(props.label as string) ?? "Submit"}
  </ShadcnButton>
);

// ─── Heading ──────────────────────────────────────────────────────────────────

const HEADING_CLASS: Record<string, string> = {
  h1: "text-2xl font-bold",
  h2: "text-lg font-semibold",
  h3: "text-base font-semibold",
  h4: "text-sm font-semibold",
};

export const Heading: StructuralComponent = ({ props }) => {
  const level = (props.level as string) ?? "h2";
  const Tag = (["h1", "h2", "h3", "h4"].includes(level) ? level : "h2") as "h1" | "h2" | "h3" | "h4";
  return (
    <Tag className={cn(HEADING_CLASS[level] ?? HEADING_CLASS.h2, props.className as string)}>
      {props.text as string}
    </Tag>
  );
};

// ─── Text ─────────────────────────────────────────────────────────────────────

const TEXT_CLASS: Record<string, string> = {
  default: "text-sm",
  muted: "text-sm text-muted-foreground",
  caption: "text-xs text-muted-foreground",
  lead: "text-xl text-muted-foreground",
  code: "font-mono text-sm bg-muted px-1.5 py-0.5 rounded",
};

export const Text: StructuralComponent = ({ props }) => {
  const variant = (props.variant as string) ?? "default";
  if (variant === "code") {
    return <code className={cn(TEXT_CLASS.code, props.className as string)}>{props.text as string}</code>;
  }
  return <p className={cn(TEXT_CLASS[variant] ?? TEXT_CLASS.default, props.className as string)}>{props.text as string}</p>;
};

// ─── Export map ───────────────────────────────────────────────────────────────

export const STRUCTURAL_COMPONENTS = { Stack, Grid, Button, Heading, Text };
